REF_MAP = {
    "https://nvd.nist.gov/vuln/detail/CVE-[0-9]{4}-[0-9]{4,}": "CVE Record",
    "https://github.com/[\w\d\-.]+/[\w\d\-.]+/pull/\d+": "GitHub Pull Request",
    "https://github.com/[\w\d\-.]+/[\w\d\-.]+/commit": "GitHub Commit",
    "https://github.com/[\w\d\-.]+/[\w\d\-.]+/release": "GitHub Repository Release",
    "https://github.com/[\w\d\-.]+/[\w\d\-.]+/?$": "GitHub Repository",
    "https://github.com/[\w\d\-.]+/[\w\d\-.]+/blob": "GitHub Blob Reference",
    "https://github.com/[\w\d\-.]+/[\w\d\-.]+/": "GitHub Other",
    "https://security.snyk.io/vuln": "Snyk Vulnerability Reference"
}


class CsafOccurence:
    def __init__(self, res):
        self.cve = res["id"]
        self.cwe = format_cwe(res["problem_type"])
        self.score = res["cvss_score"]
        self.cvss_v3 = parse_cvss(res["cvss_v3"])
        self.package_issue = res["package_issue"]
        self.product_status = {"fixed": [res["package_issue"]["fixed_location"]]} if res["package_issue"]["fixed_location"] else []
        self.description = res["short_description"]
        self.references = res["related_urls"]
        self.type = (res["type"],)
        self.pkg = res["vdetails"]["package"]
        self.severity = (res["severity"])
        self.orig_date = res["vdetails"]["source_orig_time"] if res["vdetails"]["source_orig_time"] else None
        self.update_date = res["vdetails"]["source_update_time"] if res["vdetails"]["source_update_time"] else None


def cleanup_results(results):
    for key, value in list(results.items()):
        if isinstance(value, dict):
            cleanup_results(value)  # Recursively call the function for nested dictionaries
        elif isinstance(value, list):
            results[key] = [v for v in value if v is not None and (not isinstance(v, list) or len(v) > 0)]
        elif value is None or value == [] or value == "null":
            del results[key]  # Remove key-value pair if the value is None
    return results


def format_cwe(cwe):
    if len(cwe) == 0 or cwe == [] or cwe == "[]" or cwe == "UNKNOWN":
        return None
    cwe = re.findall(r"CWE-[1-9]\d{0,5}", cwe)
    try:
        cwe = {
           "id": cwe[0],
           "name": CWE_MAP[cwe[0]],
       }
        return cwe
    except Exception as e:
        print(f"We couldn't locate the name of the CWE with the following id: {cwe}. Help us out by reporting the contents of this message at https://github.com/owasp-dep-scan/dep-scan/issues."
              f"Exception details: {e}")


def parse_cvss(cvss_v3):
    return {
        "base_score": cvss_v3["base_score"],
        "confidentiality_impact": cvss_v3["confidentiality_impact"],
        "integrity_impact": cvss_v3["integrity_impact"],
        "availability_impact": cvss_v3["availability_impact"],
        "attack_vector": cvss_v3["attack_vector"],
        "attack_complexity": cvss_v3["attack_complexity"],
        "privileges_required": cvss_v3["privileges_required"],
        "user_interaction": cvss_v3["user_interaction"],
        "scope": cvss_v3["scope"],
        "impact_score": str(cvss_v3["impact_score"]),
    }


def format_references(ref):
    new_ref = []
    for r in ref:
        new_ref.append({"summary": get_ref_summary(r), "url": r})
    return new_ref


def get_ref_summary(url):
    for pattern, value in REF_MAP.items():
        if re.match(pattern, url):
            return value
    return "Other"


def export_csaf_vuln(c):
    c.cvss_v3.update({"products": [c.pkg]})
    vuln = {}
    if c.cve.startswith("CVE"):
        vuln["cve"] = c.cve
    if len(c.references) == 0:
        print(f"Warning, could not find references for {c.cve}")
    else:
        vuln["references"] = format_references(c.references)
    if c.cwe:
        vuln["cwe"] = c.cwe
    if c.orig_date:
        vuln["discovery_date"] = c.orig_date
    elif c.update_date:
        vuln["discovery_date"] = c.update_date
    if c.product_status:
        vuln["product_status"] = c.product_status
    vuln.update({
        "notes": [
            {
                "category": "general",
                "text": c.description,
                "details": "Vulnerability Description",
            },
        ],
        "scores": [c.cvss_v3],
    })
    return vuln


def parse_revision_history(rev_hx, tracking):
    if tracking["status"].lower() == "final":
        if len(rev_hx) == 0:
            rev_hx.append({
                "date": tracking["initial_release_date"] if tracking["initial_release_date"] else str(get_date()),
                "number": "1",
                "summary": "Initial",
            })
        else:
            rev_hx.append({
                "date": tracking["current_release_date"] if tracking["current_release_date"] else str(get_date()),
                "number": str(len(rev_hx) + 1),
                "summary": "Update",
            })
    new_hx = sorted(rev_hx, key=lambda x: x["number"])
    new_hx.reverse()
    return new_hx


def set_product_tree(tree):
    product_tree = None
    if len(tree["easy_import"]) > 0:
        with open(tree["easy_import"], "r") as f:
            product_tree = json.load(f)
    return product_tree


def parse_toml(metadata):
    rev_hx = parse_revision_history(metadata["revision_history"]["revision"], metadata["tracking"])
    dt = get_date()
    refs = []
    [refs.append(v) for k, v in metadata["references"].items()]
    notes = []
    [notes.append(v) for k, v in metadata["notes"].items()]
    product_tree = set_product_tree(metadata["product_tree"])
    if not product_tree:
        raise Exception("You must include a product_tree.full_product_name entry in your toml file.")
    output = {
        "document": {
            "aggregate_severity": {},
            "category": metadata["document"]["category"],
            "title": metadata["document"]["title"] or "Test",
            "csaf_version": "2.0",
            "distribution": metadata["distribution"],
            "lang": "en",
            "notes": notes[0],
            "publisher": {
                "category": metadata["publisher"]["category"],
                "contact_details": metadata["publisher"]["contact_details"],
                "name": metadata["publisher"]["name"],
                "namespace": metadata["publisher"]["namespace"],
            },
            "references": refs[0],
            "tracking": {
                "id": metadata["tracking"]["id"],
                "current_release_date": metadata["tracking"]["current_release_date"] or rev_hx[0]["date"] or dt,
                "initial_release_date": metadata["tracking"]["initial_release_date"] or rev_hx[-1]["date"] or dt,
                "revision_history": rev_hx,
                "status": metadata["tracking"]["status"],
                "generator": {
                    "date": metadata["tracking"]["current_release_date"] or rev_hx[0]["date"] or dt,
                    "engine": {"name": "OWASP Depscan", "version": get_version()},
                },
                "version": str(metadata["tracking"]["version"]) or rev_hx[0]["number"],
            },
        },
        "product_tree": product_tree,
        "vulnerabilities": [],
    }
    if output["document"]["tracking"]["initial_release_date"] > output["document"]["tracking"]["current_release_date"]:
        raise Exception("You cannot have an initial release date later than the current date. The most likely cause "
                        "of this error is that you have included a current_release_date in your toml but not an "
                        "initial_release_date, and we have had to use the current date/time.")
    return output


def get_date():
    return str(datetime.now().isoformat())


def export_csaf(results):
    metadata = import_csaf_toml()
    template = parse_toml(metadata)
    agg_score = set()
    for r in results[0]:
        severity_ref = {
            "CRITICAL": 1,
            "HIGH": 2,
            "MEDIUM": 3,
            "LOW": 4,
        }
        c = CsafOccurence(r)
        new_vuln = export_csaf_vuln(c)
        template["vulnerabilities"].append(new_vuln)
        agg_score.add(severity_ref.get(c.severity))
    agg_score = [x for x in agg_score]
    if len(agg_score) > 0:
        agg_score.sort()
        severity_ref = {v: k for k, v in severity_ref.items()}
        agg_severity = (
            severity_ref[agg_score[0]][0] + severity_ref[agg_score[0]][1:].lower()
        )
        template["document"]["aggregate_severity"]["text"] = agg_severity
    template_cleaned = cleanup_results(template)
    json.dump(template_cleaned, open("sample.json", "w"), ensure_ascii=False, indent=4)


def import_csaf_toml():
    with open("csaf.toml", "rb") as f:
        try:
            data = tomli.load(f)
        except tomli.TOMLDecodeError as e:
            print("Invalid TOML. Please make sure you do not have any duplicate keys.")
            exit(1)
        json.dump(data, open("csaf.json", "w"), ensure_ascii=False, indent=4)
    return data


