ge.js#L97-L104', 'https://github.com/npm/node-semver/blob/main/internal/re.js#L138', 'https://github.com/npm/node-semver/blob/main/internal/re.js#L160', 'https://security.snyk.io/vuln/SNYK-JS-SEMVER-3247795'], 'effective_severity': 'MEDIUM', 'matched_by': '2237030840_2237064427|npm|semver|5.7.1', 'vdetails': {'cpe_uri': 'cpe:2.3:a:npm:semver:*:*:*:*:*:*:*:*', 'package': 'semver', 'mii': '0', 'mai': '*', 'mie': None, 'mae': '5.7.2', 'severity': 'UNSPECIFIED', 'description': None, 'fixed_location': 'cpe:2.3:a:npm:semver:5.7.2:*:*:*:*:*:*:*', 'package_type': 'npm', 'is_obsolete': None, 'source_update_time': '2023-07-10T22:57:56Z', 'source_orig_time': None}}, {'id': 'CVE-2022-25881', 'problem_type': 'CWE-1333', 'type': 'npm', 'severity': 'HIGH', 'cvss_score': '7.5', 'cvss_v3': {'base_score': 7.5, 'exploitability_score': 7.5, 'impact_score': 7.5, 'attack_vector': 'NETWORK', 'attack_complexity': 'LOW', 'privileges_required': 'NONE', 'user_interaction': 'REQUIRED', 'scope': 'UNCHANGED', 'confidentiality_impact': 'HIGH', 'integrity_impact': 'HIGH', 'availability_impact': 'HIGH'}, 'package_issue': {'affected_location': '{"cpe_uri": "cpe:2.3:a:npm:http-cache-semantics:*:*:*:*:*:*:*:*", "package": "http-cache-semantics", "version": ">=0-<4.1.1"}', 'fixed_location': '4.1.1'}, 'short_description': '# http-cache-semantics vulnerable to Regular Expression Denial of Service\nhttp-cache semantics contains an Inefficient Regular Expression Complexity , leading to Denial of Service. This affects versions of the package http-cache-semantics before 4.1.1. The issue can be exploited via malicious request header values sent to a server, when that server reads the cache policy from the request using this library.', 'long_description': None, 'related_urls': ['https://nvd.nist.gov/vuln/detail/CVE-2022-25881', 'https://github.com/kornelski/http-cache-semantics/commit/560b2d8ef452bbba20ffed69dc155d63ac757b74', 'https://github.com/kornelski/http-cache-semantics', 'https://github.com/kornelski/http-cache-semantics/blob/master/index.js%23L83', 'https://security.netapp.com/advisory/ntap-20230622-0008/', 'https://security.snyk.io/vuln/SNYK-JAVA-ORGWEBJARSNPM-3253332', 'https://security.snyk.io/vuln/SNYK-JS-HTTPCACHESEMANTICS-3248783'], 'effective_severity': 'HIGH', 'matched_by': '2324916844_2324956935|npm|http-cache-semantics|3.8.1', 'vdetails': {'cpe_uri': 'cpe:2.3:a:npm:http-cache-semantics:*:*:*:*:*:*:*:*', 'package': 'http-cache-semantics', 'mii': '0', 'mai': '*', 'mie': None, 'mae': '4.1.1', 'severity': 'UNSPECIFIED', 'description': None, 'fixed_location': 'cpe:2.3:a:npm:http-cache-semantics:4.1.1:*:*:*:*:*:*:*', 'package_type': 'npm', 'is_obsolete': None, 'source_update_time': '2023-06-22T17:31:23.446011Z', 'source_orig_time': None}}, {'id': 'CVE-2021-32803', 'problem_type': 'CWE-22,CWE-23,CWE-59', 'type': 'npm', 'severity': 'HIGH', 'cvss_score': '8.2', 'cvss_v3': {'base_score': 8.2, 'exploitability_score': 8.2, 'impact_score': 8.2, 'attack_vector': 'NETWORK', 'attack_complexity': 'LOW', 'privileges_required': 'NONE', 'user_interaction': 'REQUIRED', 'scope': 'UNCHANGED', 'confidentiality_impact': 'HIGH', 'integrity_impact': 'HIGH', 'availability_impact': 'HIGH'}, 'package_issue': {'affected_location': '{"cpe_uri": "cpe:2.3:a:npm:tar:*:*:*:*:*:*:*:*", "package": "tar", "version": ">=0-<3.2.3"}', 'fixed_location': '3.2.3'}, 'short_description': "# Arbitrary File Creation/Overwrite via insufficient symlink protection due to directory cache poisoning\n### Impact\n\nArbitrary File Creation, Arbitrary File Overwrite, Arbitrary Code Execution\n\n`node-tar` aims to guarantee that any file whose location would be modified by a symbolic link is not extracted. This is, in part, achieved by ensuring that extracted directories are not symlinks.\tAdditionally, in order to prevent unnecessary `stat` calls to determine whether a given path is a directory, paths are cached when directories are created.\n\nThis logic was insufficient when extracting tar files that contained both a directory and a symlink with the same name as the directory. This order of operations resulted in the directory being created and added to the `node-tar` directory cache. When a directory is present in the directory cache, subsequent calls to mkdir for that directory are skipped. However, this is also where `node-tar` checks for symlinks occur.\n\nBy first creating a directory, and then replacing that directory with a symlink, it was thus possible to bypass `node-tar` symlink checks on directories, essentially allowing an untrusted tar file to symlink into an arbitrary location and subsequently extracting arbitrary files into that location, thus allowing arbitrary file creation and overwrite.\n\nThis issue was addressed in releases 3.2.3, 4.4.15, 5.0.7 and 6.1.2.\n\n### Patches\n\n3.2.3 || 4.4.15 || 5.0.7 || 6.1.2\n\n### Workarounds\n\nUsers may work around this vulnerability without upgrading by creating a custom `filter` method which prevents the extraction of symbolic links.\n\n```js\nconst tar = require('tar')\n\ntar.x({\n\tfile: 'archive.tgz',\n\tfilter: (file, entry) => {\n\t\tif (entry.type === 'SymbolicLink') {\n\t\t\treturn false\n\t\t} else {\n\t\t\treturn true\n\t\t}\n\t}\n})\n```\n\nUsers are encouraged to upgrade to the latest patch versions, rather than attempt to sanitize tar input themselves.", 'long_description': None, 'related_urls': ['https://github.com/npm/node-tar/security/advisories/GHSA-r628-mhmh-qjhw', 'https://nvd.nist.gov/vuln/detail/CVE-2021-32803', 'https://github.com/isaacs/node-tar/commit/46fe35083e2676e31c4e0a81639dce6da7aaa356', 'https://github.com/isaacs/node-tar/commit/5987d9a41f6bfbf1ddab1098e1fdcf1a5618f571', 'https://github.com/isaacs/node-tar/commit/85d3a942b4064e4ff171f91696fced7975167349', 'https://github.com/isaacs/node-tar/commit/9dbdeb6df8e9dbd96fa9e84341b9d74734be6c20', 'https://github.com/npm/node-tar/commit/9dbdeb6df8e9dbd96fa9e84341b9d74734be6c20', 'https://cert-portal.siemens.com/productcert/pdf/ssa-389290.pdf', 'https://github.com/isaacs/node-tar', 'https://www.npmjs.com/advisories/1771', 'https://www.npmjs.com/package/tar', 'https://www.oracle.com/security-alerts/cpuoct2021.html'], 'effective_severity': 'HIGH', 'matched_by': '2239661362_2239707854|npm|tar|2.2.2', 'vdetails': {'cpe_uri': 'cpe:2.3:a:npm:tar:*:*:*:*:*:*:*:*', 'package': 'tar', 'mii': '0', 'mai': '*', 'mie': None, 'mae': '3.2.3', 'severity': 'UNSPECIFIED', 'description': None, 'fixed_location': 'cpe:2.3:a:npm:tar:3.2.3:*:*:*:*:*:*:*', 'package_type': 'npm', 'is_obsolete': None, 'source_update_time': '2023-03-09T16:44:57Z', 'source_orig_time': None}}, {'id': 'CVE-2023-29199', 'problem_type': 'CWE-913', 'type': 'npm', 'severity': 'CRITICAL', 'cvss_score': '9.8', 'cvss_v3': {'base_score': 9.8, 'exploitability_score': 9.8, 'impact_score': 9.8, 'attack_vector': 'NETWORK', 'attack_complexity': 'LOW', 'privileges_required': 'NONE', 'user_interaction': 'REQUIRED', 'scope': 'UNCHANGED', 'confidentiality_impact': 'CRITICAL', 'integrity_impact': 'CRITICAL', 'availability_impact': 'CRITICAL'}, 'package_issue': {'affected_location': '{"cpe_uri": "cpe:2.3:a:npm:vm2:*:*:*:*:*:*:*:*", "package": "vm2", "version": ">=0-<3.9.16"}', 'fixed_location': '3.9.16'}, 'short_description': '# vm2 Sandbox Escape vulnerability\nThere exists a vulnerability in source code transformer (exception sanitization logic) of vm2 for versions up to 3.9.15, allowing attackers to bypass `handleException()` and leak unsanitized host exceptions which can be used to escape the sandbox and run arbitrary code in host context.\n\n### Impact\nA threat actor can bypass the sandbox protections to gain remote code execution rights on the host running the sandbox.\n\n### Patches\nThis vulnerability was patched in the release of version `3.9.16` of `vm2`.\n\n### Workarounds\nNone.\n\n### References\nGithub Issue - https://github.com/patriksimek/vm2/issues/516\nPoC - https://gist.github.com/leesh3288/f05730165799bf56d70391f3d9ea187c\n\n### For more information\n\nIf you have any questions or comments about this advisory:\n\n- Open an issue in [VM2](https://github.com/patriksimek/vm2)\n\nThanks to [Xion](https://twitter.com/0x10n) (SeungHyun Lee) of [KAIST Hacking Lab](https://kaist-hacking.github.io/) for disclosing this vulnerability.', 'long_description': None, 'related_urls': ['https://github.com/patriksimek/vm2/security/advisories/GHSA-xj72-wvfv-8985', 'https://nvd.nist.gov/vuln/detail/CVE-2023-29199', 'https://github.com/patriksimek/vm2/issues/516', 'https://github.com/patriksimek/vm2/commit/24c724daa7c09f003e556d7cd1c7a8381cb985d7', 'https://gist.github.com/leesh3288/f05730165799bf56d70391f3d9ea187c', 'https://github.com/patriksimek/vm2', 'https://github.com/patriksimek/vm2/releases/tag/3.9.16'], 'effective_severity': 'CRITICAL', 'matched_by': '2240712711_2240748239|npm|vm2|3.9.13', 'vdetails': {'cpe_uri': 'cpe:2.3:a:npm:vm2:*:*:*:*:*:*:*:*', 'package': 'vm2', 'mii': '0', 'mai': '*', 'mie': None, 'mae': '3.9.16', 'severity': 'UNSPECIFIED', 'description': None, 'fixed_location': 'cpe:2.3:a:npm:vm2:3.9.16:*:*:*:*:*:*:*', 'package_type': 'npm', 'is_obsolete': None, 'source_update_time': '2023-04-14T21:35:01Z', 'source_orig_time': None}}, {'id': 'CVE-2021-37701', 'problem_type': 'CWE-22,CWE-59', 'type': 'npm', 'severity': 'HIGH', 'cvss_score': '8.2', 'cvss_v3': {'base_score': 8.2, 'exploitability_score': 8.2, 'impact_score': 8.2, 'attack_vector': 'NETWORK', 'attack_complexity': 'LOW', 'privileges_required': 'NONE', 'user_interaction': 'REQUIRED', 'scope': 'UNCHANGED', 'confidentiality_impact': 'HIGH', 'integrity_impact': 'HIGH', 'availability_impact': 'HIGH'}, 'package_issue': {'affected_location': '{"cpe_uri": "cpe:2.3:a:npm:tar:*:*:*:*:*:*:*:*", "package": "tar", "version": ">=0-<4.4.16"}', 'fixed_location': '4.4.16'}, 'short_description': "# Arbitrary File Creation/Overwrite via insufficient symlink protection due to directory cache poisoning using symbolic links\n### Impact\n\nArbitrary File Creation, Arbitrary File Overwrite, Arbitrary Code Execution\n\n`node-tar` aims to guarantee that any file whose location would be modified by a symbolic link is not extracted. This is, in part, achieved by ensuring that extracted directories are not symlinks. Additionally, in order to prevent unnecessary stat calls to determine whether a given path is a directory, paths are cached when directories are created.\n\nThis logic was insufficient when extracting tar files that contained both a directory and a symlink with the same name as the directory, where the symlink and directory names in the archive entry used backslashes as a path separator on posix systems. The cache checking logic used both `\\` and `/` characters as path separators, however `\\` is a valid filename character on posix systems.\n\nBy first creating a directory, and then replacing that directory with a symlink, it was thus possible to bypass node-tar symlink checks on directories, essentially allowing an untrusted tar file to symlink into an arbitrary location and subsequently extracting arbitrary files into that location, thus allowing arbitrary file creation and overwrite.\n\nAdditionally, a similar confusion could arise on case-insensitive filesystems.\tIf a tar archive contained a directory at `FOO`, followed by a symbolic link named `foo`, then on case-insensitive file systems, the creation of the symbolic link would remove the directory from the filesystem, but _not_ from the internal directory cache, as it would not be treated as a cache hit.\tA subsequent file entry within the `FOO` directory would then be placed in the target of the symbolic link, thinking that the directory had already been created. \n\nThese issues were addressed in releases 4.4.16, 5.0.8 and 6.1.7.\n\nThe v3 branch of `node-tar` has been deprecated and did not receive patches for these issues. If you are still using a v3 release we recommend you update to a more recent version of `node-tar`. If this is not possible, a workaround is available below.\n\n### Patches\n\n4.4.16 || 5.0.8 || 6.1.7\n\n### Workarounds\n\nUsers may work around this vulnerability without upgrading by creating a custom filter method which prevents the extraction of symbolic links.\n\n```js\nconst tar = require('tar')\n\ntar.x({\n\tfile: 'archive.tgz',\n\tfilter: (file, entry) => {\n\t\tif (entry.type === 'SymbolicLink') {\n\t\t\treturn false\n\t\t} else {\n\t\t\treturn true\n\t\t}\n\t}\n})\n```\n\nUsers are encouraged to upgrade to the latest patched versions, rather than attempt to sanitize tar input themselves.\n\n### Fix\n\nThe problem is addressed in the following ways:\n\n1. All paths are normalized to use `/` as a path separator, replacing `\\` with `/` on Windows systems, and leaving `\\` intact in the path on posix systems.\tThis is performed in depth, at every level of the program where paths are consumed.\n2. Directory cache pruning is performed case-insensitively.\tThis _may_ result in undue cache misses on case-sensitive file systems, but the performance impact is negligible.\n\n#### Caveat\n\nNote that this means that the `entry` objects exposed in various parts of tar's API will now always use `/` as a path separator, even on Windows systems.\tThis is not expected to cause problems, as `/` is a valid path separator on Windows systems, but _may_ result in issues if `entry.path` is compared against a path string coming from some other API such as `fs.realpath()` or `path.resolve()`.\n\nUsers are encouraged to always normalize paths using a well-tested method such as `path.resolve()` before comparing paths to one another.", 'long_description': None, 'related_urls': ['https://github.com/npm/node-tar/security/advisories/GHSA-9r2w-394v-53qc', 'https://nvd.nist.gov/vuln/detail/CVE-2021-37701', 'https://cert-portal.siemens.com/productcert/pdf/ssa-389290.pdf', 'https://github.com/npm/node-tar', 'https://lists.debian.org/debian-lts-announce/2022/12/msg00023.html', 'https://www.debian.org/security/2021/dsa-5008', 'https://www.npmjs.com/package/tar', 'https://www.oracle.com/security-alerts/cpuoct2021.html'], 'effective_severity': 'HIGH', 'matched_by': '2236896029_2236946781|npm|tar|2.2.2', 'vdetails': {'cpe_uri': 'cpe:2.3:a:npm:tar:*:*:*:*:*:*:*:*', 'package': 'tar', 'mii': '0', 'mai': '*', 'mie': None, 'mae': '4.4.16', 'severity': 'UNSPECIFIED', 'description': None, 'fixed_location': 'cpe:2.3:a:npm:tar:4.4.16:*:*:*:*:*:*:*', 'package_type': 'npm', 'is_obsolete': None, 'source_update_time': '2021-08-31T16:01:50Z', 'source_orig_time': None}}, {'id': 'CVE-2023-29017', 'problem_type': 'CWE-913', 'type': 'npm', 'severity': 'CRITICAL', 'cvss_score': '9.8', 'cvss_v3': {'base_score': 9.8, 'exploitability_score': 9.8, 'impact_score': 9.8, 'attack_vector': 'NETWORK', 'attack_complexity': 'LOW', 'privileges_required': 'NONE', 'user_interaction': 'REQUIRED', 'scope': 'UNCHANGED', 'confidentiality_impact': 'CRITICAL', 'integrity_impact': 'CRITICAL', 'availability_impact': 'CRITICAL'}, 'package_issue': {'affected_location': '{"cpe_uri": "cpe:2.3:a:npm:vm2:*:*:*:*:*:*:*:*", "package": "vm2", "version": ">=0-<3.9.15"}', 'fixed_location': '3.9.15'}, 'short_description': '# vm2 vulnerable to sandbox escape\nvm2 was not properly handling host objects passed to `Error.prepareStackTrace` in case of unhandled async errors.\n\n- vm2 version: ~3.9.14\n- Node version: 18.15.0, 19.8.1, 17.9.1\n\n### Impact\nA threat actor can bypass the sandbox protections to gain remote code execution rights on the host running the sandbox.\n\n### Patches\nThis vulnerability was patched in the release of version `3.9.15` of `vm2`.\n\n### Workarounds\nNone.', 'long_description': None, 'related_urls': ['https://github.com/patriksimek/vm2/security/advisories/GHSA-7jxr-cg7f-gpgv', 'https://nvd.nist.gov/vuln/detail/CVE-2023-29017', 'https://github.com/patriksimek/vm2/issues/515', 'https://github.com/patriksimek/vm2/commit/d534e5785f38307b70d3aac1945260a261a94d50', 'https://gist.github.com/seongil-wi/2a44e082001b959bfe304b62121fb76d', 'https://github.com/patriksimek/vm2'], 'effective_severity': 'CRITICAL', 'matched_by': '2236195439_2236227221|npm|vm2|3.9.13', 'vdetails': {'cpe_uri': 'cpe:2.3:a:npm:vm2:*:*:*:*:*:*:*:*', 'package': 'vm2', 'mii': '0', 'mai': '*', 'mie': None, 'mae': '3.9.15', 'severity': 'UNSPECIFIED', 'description': None, 'fixed_location': 'cpe:2.3:a:npm:vm2:3.9.15:*:*:*:*:*:*:*', 'package_type': 'npm', 'is_obsolete': None, 'source_update_time': '2023-04-07T20:35:03Z', 'source_orig_time': None}}, {'id': 'CVE-2023-28155', 'problem_type': 'CWE-918', 'type': 'npm', 'severity': 'MEDIUM', 'cvss_score': '6.1', 'cvss_v3': {'base_score': 6.1, 'exploitability_score': 6.1, 'impact_score': 6.1, 'attack_vector': 'NETWORK', 'attack_complexity': 'LOW', 'privileges_required': 'NONE', 'user_interaction': 'REQUIRED', 'scope': 'UNCHANGED', 'confidentiality_impact': 'MEDIUM', 'integrity_impact': 'MEDIUM', 'availability_impact': 'MEDIUM'}, 'package_issue': {'affected_location': '{"cpe_uri": "cpe:2.3:a:npm:request:*:*:*:*:*:*:*:*", "package": "request", "version": ">=0-<=2.88.2"}', 'fixed_location': None}, 'short_description': '# Server-Side Request Forgery in Request\nThe `request` package through 2.88.2 for Node.js and the `@cypress/request` package prior to 3.0.0 allow a bypass of SSRF mitigations via an attacker-controller server that does a cross-protocol redirect (HTTP to HTTPS, or HTTPS to HTTP).\n\nNOTE: The `request` package is no longer supported by the maintainer.', 'long_description': None, 'related_urls': ['https://nvd.nist.gov/vuln/detail/CVE-2023-28155', 'https://github.com/request/request/issues/3442', 'https://github.com/cypress-io/request/pull/28', 'https://github.com/github/advisory-database/pull/2500', 'https://github.com/request/request/pull/3444', 'https://github.com/cypress-io/request/commit/c5bcf21d40fb61feaff21a0e5a2b3934a440024f', 'https://doyensec.com/resources/Doyensec_Advisory_RequestSSRF_Q12023.pdf', 'https://github.com/cypress-io/request/blob/master/lib/redirect.js#L116', 'https://github.com/cypress-io/request/releases/tag/v3.0.0', 'https://github.com/request/request', 'https://github.com/request/request/blob/master/lib/redirect.js#L111', 'https://security.netapp.com/advisory/ntap-20230413-0007/'], 'effective_severity': 'MEDIUM', 'matched_by': '2239086110_2239117346|npm|request|2.88.2', 'vdetails': {'cpe_uri': 'cpe:2.3:a:npm:request:*:*:*:*:*:*:*:*', 'package': 'request', 'mii': '0', 'mai': '2.88.2', 'mie': None, 'mae': None, 'severity': 'UNSPECIFIED', 'description': None, 'fixed_location': 'cpe:2.3:a:npm:request::*:*:*:*:*:*:*', 'package_type': 'npm', 'is_obsolete': None, 'source_update_time': '2023-08-14T20:53:46Z', 'source_orig_time': None}}, {'id': 'CVE-2022-25883', 'problem_type': 'CWE-1333', 'type': 'npm', 'severity': 'MEDIUM', 'cvss_score': '5.3', 'cvss_v3': {'base_score': 5.3, 'exploitability_score': 5.3, 'impact_score': 5.3, 'attack_vector': 'NETWORK', 'attack_complexity': 'LOW', 'privileges_required': 'NONE', 'user_interaction': 'REQUIRED', 'scope': 'UNCHANGED', 'confidentiality_impact': 'MEDIUM', 'integrity_impact': 'MEDIUM', 'availability_impact': 'MEDIUM'}, 'package_issue': {'affected_location': '{"cpe_uri": "cpe:2.3:a:npm:semver:*:*:*:*:*:*:*:*", "package": "semver", "version": ">=6.0.0-<6.3.1"}', 'fixed_location': '6.3.1'}, 'short_description': '# semver vulnerable to Regular Expression Denial of Service\nVersions of the package semver before 7.5.2 on the 7.x branch, before 6.3.1 on the 6.x branch, and all other versions before 5.7.2 are vulnerable to Regular Expression Denial of Service (ReDoS) via the function new Range, when untrusted user data is provided as a range.', 'long_description': None, 'related_urls': ['https://nvd.nist.gov/vuln/detail/CVE-2022-25883', 'https://github.com/npm/node-semver/pull/564', 'https://github.com/npm/node-semver/pull/585', 'https://github.com/npm/node-semver/pull/593', 'https://github.com/npm/node-semver/commit/2f8fd41487acf380194579ecb6f8b1bbfe116be0', 'https://github.com/npm/node-semver/commit/717534ee353682f3bcf33e60a8af4292626d4441', 'https://github.com/npm/node-semver/commit/928e56d21150da0413a3333a3148b20e741a920c', 'https://github.com/npm/node-semver', 'https://github.com/npm/node-semver/blob/main/classes/range.js#L97-L104', 'https://github.com/npm/node-semver/blob/main/internal/re.js#L138', 'https://github.com/npm/node-semver/blob/main/internal/re.js#L160', 'https://security.snyk.io/vuln/SNYK-JS-SEMVER-3247795'], 'effective_severity': 'MEDIUM', 'matched_by': '2237030840_2237064427|npm|semver|6.3.0', 'vdetails': {'cpe_uri': 'cpe:2.3:a:npm:semver:*:*:*:*:*:*:*:*', 'package': 'semver', 'mii': '6.0.0', 'mai': '*', 'mie': None, 'mae': '6.3.1', 'severity': 'UNSPECIFIED', 'description': None, 'fixed_location': 'cpe:2.3:a:npm:semver:6.3.1:*:*:*:*:*:*:*', 'package_type': 'npm', 'is_obsolete': None, 'source_update_time': '2023-07-10T22:57:56Z', 'source_orig_time': None}}, {'id': 'CVE-2021-32804', 'problem_type': 'CWE-22', 'type': 'npm', 'severity': 'HIGH', 'cvss_score': '8.2', 'cvss_v3': {'base_score': 8.2, 'exploitability_score': 8.2, 'impact_score': 8.2, 'attack_vector': 'NETWORK', 'attack_complexity': 'LOW', 'privileges_required': 'NONE', 'user_interaction': 'REQUIRED', 'scope': 'UNCHANGED', 'confidentiality_impact': 'HIGH', 'integrity_impact': 'HIGH', 'availability_impact': 'HIGH'}, 'package_issue': {'affected_location': '{"cpe_uri": "cpe:2.3:a:npm:tar:*:*:*:*:*:*:*:*", "package": "tar", "version": ">=0-<3.2.2"}', 'fixed_location': '3.2.2'}, 'short_description': "# Arbitrary File Creation/Overwrite due to insufficient absolute path sanitization\n### Impact\n\nArbitrary File Creation, Arbitrary File Overwrite, Arbitrary Code Execution\n\n`node-tar` aims to prevent extraction of absolute file paths by turning absolute paths into relative paths when the `preservePaths` flag is not set to `true`. This is achieved by stripping the absolute path root from any absolute file paths contained in a tar file. For example `/home/user/.bashrc` would turn into `home/user/.bashrc`. \n\nThis logic was insufficient when file paths contained repeated path roots such as `////home/user/.bashrc`. `node-tar` would only strip a single path root from such paths. When given an absolute file path with repeating path roots, the resulting path (e.g. `///home/user/.bashrc`) would still resolve to an absolute path, thus allowing arbitrary file creation and overwrite. \n\n### Patches\n\n3.2.2 || 4.4.14 || 5.0.6 || 6.1.1\n\nNOTE: an adjacent issue [CVE-2021-32803](https://github.com/npm/node-tar/security/advisories/GHSA-r628-mhmh-qjhw) affects this release level. Please ensure you update to the latest patch levels that address CVE-2021-32803 as well if this adjacent issue affects your `node-tar` use case.\n\n### Workarounds\n\nUsers may work around this vulnerability without upgrading by creating a custom `onentry` method which sanitizes the `entry.path` or a `filter` method which removes entries with absolute paths.\n\n```js\nconst path = require('path')\nconst tar = require('tar')\n\ntar.x({\n\tfile: 'archive.tgz',\n\t// either add this function...\n\tonentry: (entry) => {\n\t\tif (path.isAbsolute(entry.path)) {\n\t\t\tentry.path = sanitizeAbsolutePathSomehow(entry.path)\n\t\t\tentry.absolute = path.resolve(entry.path)\n\t\t}\n\t},\n\n\t// or this one\n\tfilter: (file, entry) => {\n\t\tif (path.isAbsolute(entry.path)) {\n\t\t\treturn false\n\t\t} else {\n\t\t\treturn true\n\t\t}\n\t}\n})\n```\n\nUsers are encouraged to upgrade to the latest patch versions, rather than attempt to sanitize tar input themselves.", 'long_description': None, 'related_urls': ['https://github.com/npm/node-tar/security/advisories/GHSA-3jfq-g458-7qm9', 'https://nvd.nist.gov/vuln/detail/CVE-2021-32804', 'https://github.com/npm/node-tar/commit/1f036ca23f64a547bdd6c79c1a44bc62e8115da4', 'https://cert-portal.siemens.com/productcert/pdf/ssa-389290.pdf', 'https://github.com/npm/node-tar', 'https://www.npmjs.com/advisories/1770', 'https://www.npmjs.com/package/tar', 'https://www.oracle.com/security-alerts/cpuoct2021.html'], 'effective_severity': 'HIGH', 'matched_by': '2234746351_2234792060|npm|tar|2.2.2', 'vdetails': {'cpe_uri': 'cpe:2.3:a:npm:tar:*:*:*:*:*:*:*:*', 'package': 'tar', 'mii': '0', 'mai': '*', 'mie': None, 'mae': '3.2.2', 'severity': 'UNSPECIFIED', 'description': None, 'fixed_location': 'cpe:2.3:a:npm:tar:3.2.2:*:*:*:*:*:*:*', 'package_type': 'npm', 'is_obsolete': None, 'source_update_time': '2021-08-30T23:14:50Z', 'source_orig_time': None}}, {'id': 'CVE-2023-26115', 'problem_type': 'CWE-1333', 'type': 'npm', 'severity': 'MEDIUM', 'cvss_score': '5.3', 'cvss_v3': {'base_score': 5.3, 'exploitability_score': 5.3, 'impact_score': 5.3, 'attack_vector': 'NETWORK', 'attack_complexity': 'LOW', 'privileges_required': 'NONE', 'user_interaction': 'REQUIRED', 'scope': 'UNCHANGED', 'confidentiality_impact': 'MEDIUM', 'integrity_impact': 'MEDIUM', 'availability_impact': 'MEDIUM'}, 'package_issue': {'affected_location': '{"cpe_uri": "cpe:2.3:a:npm:word-wrap:*:*:*:*:*:*:*:*", "package": "word-wrap", "version": ">=0-<1.2.4"}', 'fixed_location': '1.2.4'}, 'short_description': '# word-wrap vulnerable to Regular Expression Denial of Service\nAll versions of the package word-wrap are vulnerable to Regular Expression Denial of Service (ReDoS) due to the usage of an insecure regular expression within the result variable.', 'long_description': None, 'related_urls': ['https://nvd.nist.gov/vuln/detail/CVE-2023-26115', 'https://github.com/jonschlinkert/word-wrap/commit/420dce9a2412b21881202b73a3c34f0edc53cb2e', 'https://github.com/jonschlinkert/word-wrap', 'https://github.com/jonschlinkert/word-wrap/blob/master/index.js#L39', 'https://github.com/jonschlinkert/word-wrap/blob/master/index.js%23L39', 'https://github.com/jonschlinkert/word-wrap/releases/tag/1.2.4', 'https://security.snyk.io/vuln/SNYK-JAVA-ORGWEBJARSNPM-4058657', 'https://security.snyk.io/vuln/SNYK-JS-WORDWRAP-3149973'], 'effective_severity': 'MEDIUM', 'matched_by': '22383954